func GetOrder(ctx context.Context, id string) (*Order, error) {
    data, err := rdb.Get(ctx, "order:"+id).Bytes()
    if err != nil {
        return nil, fmt.Errorf("cache error: %w", err)  // Redis down = 500 to user
    }
    var order Order
    json.Unmarshal(data, &order)
    return &order, nil
}
